// Chinese (zh) + Vietnamese (vi) translations for product intro and
// feature bullets, keyed by catalog slug. Generated from the client-supplied
// per-brand product JSON (data/i18n/products/*.json). Full spec tables are
// preserved in those JSON files for a later grouped-spec upgrade.

export type LocalizedText = { en: string; zh: string; vi: string };
export type LocalizedList = { en: string[]; zh: string[]; vi: string[] };
export type ProductI18n = { intro?: LocalizedText; features?: LocalizedList };

export const productI18n: Record<string, ProductI18n> = {
  "ac2": { intro: {"en": "Compact AC275 and AC2110 air-cooled UV LED heads provide uniform small-area curing over 75 mm or 114 mm lengths, with up to 3 W/cm² at 365 nm and 4 W/cm² at 395 nm.", "zh": "AC2 系列包含结构紧凑的 AC275 与 AC2110 风冷 UV LED 灯头，分别覆盖 75 mm 与 114 mm 固化长度；365 nm 型号最高 3 W/cm²，395 nm 型号最高 4 W/cm²。", "vi": "Hệ thống đóng rắn UV LED làm mát bằng khí AC275 và AC2110 có thiết kế nhỏ gọn, lý tưởng cho các ứng dụng hạn chế không gian, sử dụng quang học mặt trước tiên tiến để đạt độ rọi đỉnh cao và độ đồng đều vượt trội. Phù hợp cho ứng dụng in ấn, thiết bị y tế, điện tử và quang điện tử."}, features: {"en": ["75 mm and 114 mm curing lengths", "365 nm and 395 nm wavelength options"], "zh": ["提供 75 mm 与 114 mm 两种固化长度", "支持 365 nm 与 395 nm 波长"], "vi": ["Kích thước nhỏ gọn, lý tưởng cho lắp đặt hạn chế không gian", "Quang học mặt trước tiên tiến cho độ rọi đỉnh cao và độ đồng đều"]} },
  "ac4": { intro: {"en": "AC450/P and AC475/P air-cooled UV LED heads deliver 8 W/cm² over 50 mm or 75 mm curing lengths at 365 nm or 395 nm. Print variants use application-specific optics.", "zh": "AC4 系列的 AC450/P 与 AC475/P 风冷 UV LED 灯头在 50 mm 或 75 mm 固化长度上提供 8 W/cm² 峰值辐照度，支持 365 nm 与 395 nm；P 型为印刷应用优化光学版本。", "vi": "Hệ thống đóng rắn UV LED diện tích nhỏ làm mát bằng khí AC450/P và AC475/P cung cấp độ rọi cao (8 W/cm²) ở khoảng cách làm việc linh hoạt, lý tưởng cho lắp ráp thiết bị y tế và ứng dụng điện tử cần đóng rắn năng suất cao, nhiệt độ thấp."}, features: {"en": ["8 W/cm² at 365 nm or 395 nm", "50 mm and 75 mm curing lengths"], "zh": ["365 nm 或 395 nm 下提供 8 W/cm²", "提供 50 mm 与 75 mm 两种固化长度"], "vi": ["Độ rọi cao 8 W/cm² ở khoảng cách làm việc linh hoạt", "Phù hợp đóng rắn năng suất cao, nhiệt độ thấp cho linh kiện nhựa"]} },
  "ac5": { intro: {"en": "AC550/P and AC575/P heads deliver 14 W/cm² at 395 nm; AC575-405 delivers 15 W/cm² at 405 nm. The compact, air-cooled heads require no external chiller or ozone extraction.", "zh": "AC5 系列的 AC550/P 与 AC575/P 在 395 nm 下提供 14 W/cm²，AC575-405 在 405 nm 下可达 15 W/cm²。灯头结构紧凑、采用风冷，无需外部冷水机或臭氧排放。", "vi": "Hệ thống UV LED làm mát bằng khí AC5 được thiết kế với sự kết hợp độc đáo giữa LED công suất cao và quang học tùy chỉnh, đạt tới 14 W/cm², cung cấp độ rọi cao ở khoảng cách làm việc linh hoạt. Thiết kế đầu nhỏ gọn loại bỏ nhu cầu làm mát ngoài hoặc hút khí ozone, đơn giản hóa tích hợp, và có thể lắp đặt theo mọi hướng."}, features: {"en": ["14 W/cm² at 395 nm; 15 W/cm² with AC575-405", "No external chiller or ozone extraction"], "zh": ["395 nm 下为 14 W/cm²；AC575-405 可达 15 W/cm²", "无需外部冷水机或臭氧排放"], "vi": ["Độ rọi đỉnh lên đến 14-15 W/cm²", "Không cần làm mát ngoài hay hút ozone; lắp đặt theo mọi hướng"]} },
  "ac7": { intro: {"en": "AC7150 and AC7300 air-cooled heads provide uniform 150 mm or 300 mm curing lengths, delivering 3 W/cm² at 365 nm or 5 W/cm² at 395 nm. Multiple heads can be adjoined.", "zh": "AC7 系列的 AC7150 与 AC7300 风冷灯头分别提供 150 mm 与 300 mm 固化长度；365 nm 下为 3 W/cm²，395 nm 下为 5 W/cm²，并支持多灯头拼接。", "vi": "AC7150 và AC7300 cung cấp độ đồng đều vượt trội trên toàn bộ vùng đóng rắn để đóng rắn đều và nhất quán. Nhiều hệ thống có thể ghép nối mà không ảnh hưởng độ đồng đều, mang lại tính linh hoạt cao hơn khi đóng rắn các bộ phận lớn hơn. Thiết kế cho lắp ráp thiết bị y tế, điện tử, ô tô, sợi quang và ứng dụng công nghiệp."}, features: {"en": ["150 mm and 300 mm curing lengths", "3 W/cm² at 365 nm; 5 W/cm² at 395 nm"], "zh": ["提供 150 mm 与 300 mm 两种固化长度", "365 nm 下 3 W/cm²；395 nm 下 5 W/cm²"], "vi": ["Độ đồng đều vượt trội trên toàn vùng đóng rắn", "Có thể ghép nhiều hệ thống để mở rộng vùng đóng rắn mà không mất độ đồng đều"]} },
  "ac8": { intro: {"en": "The AC8150/P, AC8225/P and AC8300/P air-cooled UV LED curing systems deliver over 8 W/cm2 peak irradiance for fast, even curing at long working distances. \"P\" versions feature enhanced optics optimized for short working distances required by print applications.", "zh": "AC8150/P、AC8225/P与AC8300/P风冷式UV LED固化系统峰值辐照度超过8 W/cm²，在长工作距离下实现快速均匀固化。\"P\"版本配备增强光学设计，专为印刷应用所需的短工作距离优化。", "vi": "Hệ thống đóng rắn UV LED làm mát bằng khí AC8150/P, AC8225/P và AC8300/P đạt độ rọi đỉnh trên 8 W/cm², đóng rắn nhanh và đều ở khoảng cách làm việc xa. Phiên bản \"P\" có quang học tăng cường tối ưu cho khoảng cách làm việc ngắn cần thiết trong ứng dụng in ấn."}, features: {"en": ["Over 8 W/cm2 peak irradiance for fast, even curing at long working distances", "\"P\" print versions optimized for short working distances"], "zh": ["峰值辐照度超过8 W/cm²，长工作距离下实现快速均匀固化", "\"P\"印刷版本针对短工作距离优化"], "vi": ["Độ rọi đỉnh trên 8 W/cm², đóng rắn nhanh đều ở khoảng cách xa", "Phiên bản in \"P\" tối ưu cho khoảng cách làm việc ngắn"]} },
  "ac8-hd": { intro: {"en": "The AC8-HD Series brings air-cooled UV LED curing to the next level, delivering over 15 W/cm2 peak irradiance and nearly double the dose of the AC8 Series, with innovative technology enabling unbeatable uniformity across the irradiation area. Offers three standard cure widths (6\", 9\", 12\") that can be adjoined for customized curing sizes.", "zh": "AC8-HD系列将风冷式UV LED固化技术推向新高度，峰值辐照度超过15 W/cm²，剂量几乎是AC8系列的两倍，并通过创新技术实现整个照射区域内无可匹敌的均匀性。提供三种标准固化宽度（6英寸、9英寸、12英寸），可拼接组合以定制固化尺寸。", "vi": "Dòng AC8-HD đưa công nghệ đóng rắn UV LED làm mát bằng khí lên một tầm cao mới, đạt độ rọi đỉnh trên 15 W/cm² và liều gần gấp đôi dòng AC8, với công nghệ đột phá mang lại độ đồng đều vượt trội trên toàn vùng chiếu xạ. Có ba độ rộng đóng rắn tiêu chuẩn (6\", 9\", 12\") có thể ghép nối để tùy chỉnh kích thước đóng rắn."}, features: {"en": ["Over 15 W/cm2 peak irradiance, nearly double the dose of AC8 Series", "Three standard cure widths adjoinable for customized sizes"], "zh": ["峰值辐照度超过15 W/cm²，剂量近乎AC8系列的两倍", "三种标准固化宽度，可拼接定制尺寸"], "vi": ["Độ rọi đỉnh trên 15 W/cm², liều gần gấp đôi dòng AC8", "Ba độ rộng đóng rắn tiêu chuẩn, có thể ghép nối tùy chỉnh kích thước"]} },
  "ac9225": { intro: {"en": "The AC9 Series delivers 14 W/cm² in 150 mm, 225 mm and 300 mm air-cooled formats at 385 nm or 395 nm. Print variants at 395 nm are optimized for short working distances.", "zh": "AC9 系列在 150 mm、225 mm 与 300 mm 三种风冷规格中提供 14 W/cm²，支持 385 nm 与 395 nm；395 nm 的 P 型为短工作距离印刷应用优化。", "vi": "Dòng AC9 là hệ thống đóng rắn UV LED công suất cao, đạt độ rọi đỉnh trên 14 W/cm² để đóng rắn nhanh mực in, keo dán và sơn phủ. Thiết kế đột phá với giải pháp làm mát bằng khí hiệu suất cao, kích thước nhỏ gọn, cho phép tốc độ dây chuyền nhanh. Điều khiển từng mô-đun LED riêng lẻ mang lại độ đồng đều vượt trội, thiết kế mở rộng cho phép ghép nối nhiều đầu."}, features: {"en": ["14 W/cm² peak irradiance", "150 mm, 225 mm and 300 mm lengths", "385 nm and 395 nm options"], "zh": ["峰值辐照度 14 W/cm²", "提供 150 mm、225 mm 与 300 mm 三种长度", "支持 385 nm 与 395 nm"], "vi": ["Độ rọi đỉnh trên 14 W/cm² để đóng rắn nhanh", "Điều khiển mô-đun LED riêng lẻ cho độ đồng đều đóng rắn vượt trội", "Thiết kế mở rộng — có thể ghép nối nhiều đầu"]} },
  "ac9225-f": { intro: {"en": "Specifically designed for fiber curing applications, the AC9225-F delivers up to 88 W/cm2 peak irradiance at the fiber in typical face-to-face configuration, with 10-18mm working distance. Reduces electrical power consumption by up to 60% compared to traditional arc lamp systems, with over 40,000 hours of LED lifetime and no replacement parts.", "zh": "AC9225-F专为光纤固化应用设计，在典型面对面配置下可实现高达88 W/cm²的峰值辐照度，工作距离为10-18毫米。相较传统电弧灯系统，可节省高达60%的电力消耗，LED寿命超过40,000小时，无需更换部件。", "vi": "Được thiết kế riêng cho ứng dụng đóng rắn sợi quang, AC9225-F đạt độ rọi đỉnh lên đến 88 W/cm² tại sợi quang trong cấu hình đối diện điển hình, khoảng cách làm việc 10-18mm. Giảm tiêu thụ điện lên đến 60% so với hệ thống đèn hồ quang truyền thống, tuổi thọ LED trên 40.000 giờ và không cần thay thế linh kiện."}, features: {"en": ["Up to 88 W/cm2 peak irradiance at the fiber", "Reduces power consumption by up to 60% vs. arc lamp systems", "Over 40,000 hours LED lifetime with no replacement parts"], "zh": ["光纤处峰值辐照度高达88 W/cm²", "相较电弧灯系统，节省高达60%电力消耗", "LED寿命超过40,000小时，无需更换部件"], "vi": ["Độ rọi đỉnh tại sợi quang lên đến 88 W/cm²", "Giảm tiêu thụ điện đến 60% so với hệ thống đèn hồ quang", "Tuổi thọ LED trên 40.000 giờ, không cần thay thế linh kiện"]} },
  "f-series": { intro: {"en": "An economical electrodeless UV lamp system offering unlimited cure width by stacking lamps end-to-end. Features a semi-elliptical reflector geometry, optional dichroic reflectors, and optional mechanical shutter, suitable for a broad range of standard industrial UV curing applications.", "zh": "经济型无极UV灯系统，可通过首尾拼接灯具实现无限固化宽度。采用半椭圆反射器几何设计，可选配二向色反射器与机械快门，适用于各类标准工业UV光固化应用。", "vi": "Hệ thống đèn UV không điện cực kinh tế, cho phép độ rộng đóng rắn không giới hạn bằng cách ghép nối các đèn nối tiếp. Có hình học gương phản xạ bán elip, gương phản xạ lưỡng sắc tùy chọn, và cửa chớp cơ học tùy chọn, phù hợp cho nhiều ứng dụng đóng rắn UV công nghiệp tiêu chuẩn."}, features: {"en": ["Unlimited cure width by stacking lamps end-to-end", "Fast startup: 20s cold start, 5s warm start (F300S/F300SQ)", "Standard external control and remote cooling blower"], "zh": ["灯具可首尾拼接，实现无限固化宽度", "启动迅速：冷启动20秒，热启动5秒（F300S/F300SQ）", "标配外部控制与远程冷却风机"], "vi": ["Độ rộng đóng rắn không giới hạn bằng ghép nối đèn nối tiếp", "Khởi động nhanh: khởi động nguội 20s, khởi động nóng 5s (F300S/F300SQ)", "Điều khiển ngoài tiêu chuẩn và quạt làm mát từ xa"]} },
  "fe100": { intro: {"en": "A natural convection-cooled UV LED system with WhisperCure technology, a thin form factor, and analog control, designed for pinning and gelling applications.", "zh": "采用自然对流冷却的UV LED系统，搭载WhisperCure技术，机身轻薄，支持模拟控制，专为点固化与凝胶化应用设计。", "vi": "Hệ thống UV LED làm mát bằng đối lưu tự nhiên với công nghệ WhisperCure, kích thước mỏng, và điều khiển tương tự, được thiết kế cho ứng dụng định hình và đông gel."}, features: {"en": ["Natural convection cooling, no fan required", "Thin form factor designed for pinning and gelling"], "zh": ["自然对流冷却，无需风扇", "机身轻薄，专为点固化与凝胶化设计"], "vi": ["Làm mát đối lưu tự nhiên, không cần quạt", "Kích thước mỏng, thiết kế cho định hình và đông gel"]} },
  "fe410": { intro: {"en": "An air-cooled UV LED system with TargetCure and WhisperCure technology delivering full cure, optics options, analog control, and a small form factor.", "zh": "风冷式UV LED系统，搭载TargetCure与WhisperCure技术，实现完全固化，提供光学选配方案，支持模拟控制，体积小巧。", "vi": "Hệ thống UV LED làm mát bằng khí với công nghệ TargetCure và WhisperCure mang lại đóng rắn hoàn toàn, tùy chọn quang học, điều khiển tương tự, và kích thước nhỏ gọn."}, features: {"en": ["Full cure with TargetCure and WhisperCure technology", "Optics options available, small form factor"], "zh": ["搭载TargetCure与WhisperCure技术，实现完全固化", "提供光学选配方案，体积小巧"], "vi": ["Đóng rắn hoàn toàn với công nghệ TargetCure và WhisperCure", "Có tùy chọn quang học, kích thước nhỏ gọn"]} },
  "firejet-one": { intro: {"en": "An air-cooled UV LED system with TargetCure and WhisperCure technology, offering high irradiance in a small, scalable form factor with optional Ethernet communication.", "zh": "风冷式UV LED系统，搭载TargetCure与WhisperCure技术，体积小巧、可扩展，提供高辐照度，并支持可选以太网通信。", "vi": "Hệ thống UV LED làm mát bằng khí với công nghệ TargetCure và WhisperCure, mang lại độ rọi cao trong kích thước nhỏ gọn, có thể mở rộng, với giao tiếp Ethernet tùy chọn."}, features: {"en": ["TargetCure and WhisperCure technology", "High irradiance in a small, scalable form factor"], "zh": ["搭载TargetCure与WhisperCure技术", "体积小巧可扩展，辐照度高"], "vi": ["Công nghệ TargetCure và WhisperCure", "Độ rọi cao trong kích thước nhỏ gọn, có thể mở rộng"]} },
  "fj100": { intro: {"en": "An air-cooled, scalable UV LED system with TargetCure and WhisperCure technology, digital/analog control, and optional Ethernet communication for high irradiance curing applications.", "zh": "风冷式、可扩展的UV LED系统，搭载TargetCure与WhisperCure技术，支持数字/模拟控制及可选以太网通信，适用于高辐照度固化应用。", "vi": "Hệ thống UV LED làm mát bằng khí, có thể mở rộng với công nghệ TargetCure và WhisperCure, điều khiển số/tương tự, và giao tiếp Ethernet tùy chọn cho ứng dụng đóng rắn độ rọi cao."}, features: {"en": ["TargetCure and WhisperCure technology", "Digital/analog control with optional Ethernet communication"], "zh": ["搭载TargetCure与WhisperCure技术", "支持数字/模拟控制及可选以太网通信"], "vi": ["Công nghệ TargetCure và WhisperCure", "Điều khiển số/tương tự với giao tiếp Ethernet tùy chọn"]} },
  "fj240": { intro: {"en": "An air-cooled, scalable UV LED system featuring TargetCure technology and high dose output, with digital/analog control and optional Ethernet communication.", "zh": "风冷式、可扩展的UV LED系统，搭载TargetCure技术，提供高剂量输出，支持数字/模拟控制及可选以太网通信。", "vi": "Hệ thống UV LED làm mát bằng khí, có thể mở rộng với công nghệ TargetCure và đầu ra liều cao, điều khiển số/tương tự và giao tiếp Ethernet tùy chọn."}, features: {"en": ["High dose output with TargetCure technology", "Scalable design with digital/analog control"], "zh": ["搭载TargetCure技术，提供高剂量输出", "可扩展设计，支持数字/模拟控制"], "vi": ["Đầu ra liều cao với công nghệ TargetCure", "Thiết kế mở rộng với điều khiển số/tương tự"]} },
  "fj801": { intro: {"en": "An air-cooled UV LED area curing system featuring TargetCure technology, exceptional uniformity, and a separate controller, designed for area curing applications.", "zh": "风冷式UV LED面固化系统，搭载TargetCure技术，均匀性卓越，配备独立控制器，专为面固化应用设计。", "vi": "Hệ thống đóng rắn diện tích UV LED làm mát bằng khí với công nghệ TargetCure, độ đồng đều vượt trội, và bộ điều khiển riêng, được thiết kế cho ứng dụng đóng rắn diện tích."}, features: {"en": ["Exceptional uniformity for area curing applications", "Separate controller, scalable design"], "zh": ["面固化应用中均匀性卓越", "配备独立控制器，可扩展设计"], "vi": ["Độ đồng đều vượt trội cho ứng dụng đóng rắn diện tích", "Bộ điều khiển riêng, thiết kế mở rộng"]} },
  "fl200": { intro: {"en": "A water-cooled, scalable, small form factor UV LED system with a separate controller and Ethernet control, designed for compact installation requirements.", "zh": "水冷式、可扩展、体积小巧的UV LED系统，配备独立控制器，支持以太网控制，专为紧凑安装需求设计。", "vi": "Hệ thống UV LED làm mát bằng nước, có thể mở rộng, kích thước nhỏ gọn với bộ điều khiển riêng và điều khiển Ethernet, được thiết kế cho yêu cầu lắp đặt nhỏ gọn."}, features: {"en": ["Small form factor with separate controller", "Ethernet control for system integration"], "zh": ["体积小巧，配备独立控制器", "支持以太网控制，便于系统集成"], "vi": ["Kích thước nhỏ gọn với bộ điều khiển riêng", "Điều khiển Ethernet để tích hợp hệ thống"]} },
  "fl400": { intro: {"en": "A water-cooled, scalable UV LED system with digital/analog control, designed for high performance curing applications with optional Ethernet communication.", "zh": "水冷式、可扩展的UV LED系统，支持数字/模拟控制，专为高性能固化应用设计，并支持可选以太网通信。", "vi": "Hệ thống UV LED làm mát bằng nước, có thể mở rộng với điều khiển số/tương tự, được thiết kế cho ứng dụng đóng rắn hiệu suất cao với giao tiếp Ethernet tùy chọn."}, features: {"en": ["Scalable design with digital/analog control", "Suited for high performance curing applications"], "zh": ["可扩展设计，支持数字/模拟控制", "适用于高性能固化应用"], "vi": ["Thiết kế mở rộng với điều khiển số/tương tự", "Phù hợp cho ứng dụng đóng rắn hiệu suất cao"]} },
  "fl440": { intro: {"en": "A water-cooled, scalable UV LED system delivering high dose and high irradiance with digital/analog control, suited for high performance curing applications with optional Ethernet communication.", "zh": "水冷式、可扩展的UV LED系统，提供高剂量与高辐照度，支持数字/模拟控制，适用于高性能固化应用，并支持可选以太网通信。", "vi": "Hệ thống UV LED làm mát bằng nước, có thể mở rộng, mang lại liều cao và độ rọi cao với điều khiển số/tương tự, phù hợp cho ứng dụng đóng rắn hiệu suất cao với giao tiếp Ethernet tùy chọn."}, features: {"en": ["High dose and high irradiance output", "Suited for high performance curing applications"], "zh": ["提供高剂量与高辐照度输出", "适用于高性能固化应用"], "vi": ["Đầu ra liều cao và độ rọi cao", "Phù hợp cho ứng dụng đóng rắn hiệu suất cao"]} },
  "lighthammer-10": { intro: {"en": "The ultra high output 10-inch lamp system and flagship of the Fusion UV range, delivering the full 240 W/cm power class with electronic shutter, variable power control, and optional industrial fieldbus protocols. Represents the latest generation of LightHammer technology with CE compliance.", "zh": "超高输出10英寸灯具系统，是Fusion UV产品线的旗舰型号，提供全功率等级240 瓦/厘米，配备电子快门、可变功率控制及可选工业现场总线协议。代表LightHammer技术的最新一代，符合CE认证标准。", "vi": "Hệ thống đèn 10 inch đầu ra siêu cao và là sản phẩm chủ lực của dòng Fusion UV, cung cấp cấp công suất đầy đủ 240 W/cm với cửa chớp điện tử, điều khiển công suất biến thiên, và giao thức fieldbus công nghiệp tùy chọn. Đại diện cho thế hệ công nghệ LightHammer mới nhất, đạt chứng nhận CE."}, features: {"en": ["Ultra high output flagship of the Fusion UV product range", "Electronic shutter and variable power (35-100%)", "Optional industrial fieldbus protocol support"], "zh": ["Fusion UV产品线超高输出旗舰型号", "电子快门与可变功率（35-100%）", "可选支持工业现场总线协议"], "vi": ["Sản phẩm chủ lực đầu ra siêu cao của dòng Fusion UV", "Cửa chớp điện tử và công suất biến thiên (35-100%)", "Hỗ trợ giao thức fieldbus công nghiệp tùy chọn"]} },
  "lighthammer-6": { intro: {"en": "A 6-inch electrodeless UV lamp system with variable power (35-100%) and quick restart, electronic shutter, and standard primary/secondary external control with optional industrial fieldbus protocols (DeviceNet, Profinet, Profibus, EtherNet/IP).", "zh": "采用6英寸灯泡的无极UV灯系统，支持可变功率（35-100%）及快速重启、电子快门，以及标配主/从外部控制，并可选配工业现场总线协议（DeviceNet、Profinet、Profibus、EtherNet/IP）。", "vi": "Hệ thống đèn UV không điện cực 6 inch với công suất biến thiên (35-100%) và khởi động lại nhanh, cửa chớp điện tử, và điều khiển ngoài chính/phụ tiêu chuẩn với giao thức fieldbus công nghiệp tùy chọn (DeviceNet, Profinet, Profibus, EtherNet/IP)."}, features: {"en": ["Variable power (35-100%) with quick restart capability", "Electronic shutter standard, optional mechanical", "Optional industrial fieldbus protocol support"], "zh": ["支持可变功率（35-100%），可快速重启", "标配电子快门，可选机械快门", "可选支持工业现场总线协议"], "vi": ["Công suất biến thiên (35-100%) với khả năng khởi động lại nhanh", "Cửa chớp điện tử tiêu chuẩn, tùy chọn cơ học", "Hỗ trợ giao thức fieldbus công nghiệp tùy chọn"]} },
  "ls200": { intro: {"en": "Radiometry is essential for measuring light output from a UV curing system to maintain a precise, repeatable process. UV measuring systems must capture the narrow beam at the center of a detecting sensor at an exact focal height to determine peak irradiance. Two options are available: Irradiance (W/cm2) using the LS200 or Optical Power (W) using the LS200P, achieving unmatched control when used with a Beam Positioning Kit and LX500 controller.", "zh": "辐射测量是维持精准、可重复UV光固化工艺的关键，用于测量UV光固化系统的光输出。UV测量系统必须在精确焦距高度内、于检测传感器中心捕获窄光束，才能确定峰值辐照度。提供两种测量方案：使用LS200测量辐照度（W/cm²），或使用LS200P测量光功率（W）；搭配光束定位套件与LX500控制器使用时，可实现无可比拟的控制精度。", "vi": "Đo bức xạ là kỹ thuật thiết yếu để đo đầu ra ánh sáng từ hệ thống đóng rắn UV nhằm duy trì quy trình chính xác, có thể lặp lại. Hệ thống đo UV phải bắt được chùm tia hẹp tại tâm cảm biến ở đúng độ cao tiêu cự để xác định độ rọi đỉnh. Có hai tùy chọn: đo độ rọi (W/cm²) bằng LS200 hoặc công suất quang (W) bằng LS200P, đạt khả năng kiểm soát vượt trội khi dùng cùng Bộ định vị chùm tia và bộ điều khiển LX500."}, features: {"en": ["Accurate measurement with +/-10% accuracy and high resolution", "Optimized for monochromatic UV LED sources", "Compact design suitable for confined-area measurements"], "zh": ["测量精准，误差±10%，分辨率高", "针对单色UV LED光源优化", "紧凑设计，适合狭小空间测量"], "vi": ["Đo chính xác với độ chính xác +/-10% và độ phân giải cao", "Tối ưu cho nguồn UV LED đơn sắc", "Thiết kế nhỏ gọn phù hợp đo trong không gian hẹp"]} },
  "lx500": { intro: {"en": "The LX500 V2 series delivers outstanding optical stability with proprietary Intelli-Lamp LED technology, exceptionally high peak irradiance, and unparalleled process control with StepCure 2.0. A newly designed 2.4-inch full color LCD provides flexible control via keypad, foot pedal, PLC, or USB, with real-time programming and data logging via Micro SD card.", "zh": "LX500 V2系列搭载专利Intelli-Lamp LED技术，光学稳定性出众，峰值辐照度极高，并通过StepCure 2.0实现无与伦比的工艺控制。全新设计的2.4英寸全彩液晶屏支持四向按键、脚踏开关、PLC或USB等多种控制方式，并可通过Micro SD卡实现实时编程与数据记录。", "vi": "Dòng LX500 V2 mang lại độ ổn định quang học vượt trội nhờ công nghệ Intelli-Lamp LED độc quyền, độ rọi đỉnh cực cao, và khả năng kiểm soát quy trình vô song với StepCure 2.0. Màn hình LCD màu 2.4 inch thiết kế mới cho phép điều khiển linh hoạt qua bàn phím, bàn đạp, PLC hoặc USB, cùng lập trình thời gian thực và ghi log dữ liệu qua thẻ Micro SD."}, features: {"en": ["Intelli-Lamp LED technology maintains optical stability +/-5% during exposure", "Integrated radiometer for quick calibration and accurate intensity measurement", "2.4-inch full color LCD with four-way keypad, foot pedal, PLC, or USB control"], "zh": ["Intelli-Lamp LED技术在曝光过程中保持±5%的光学稳定性", "集成辐射计，实现快速校准与精准强度测量", "2.4英寸全彩液晶屏，支持四向按键、脚踏、PLC或USB多种控制方式"], "vi": ["Công nghệ Intelli-Lamp LED duy trì độ ổn định quang học +/-5% trong khi phơi sáng", "Máy đo bức xạ tích hợp để hiệu chuẩn nhanh và đo cường độ chính xác", "Màn hình LCD màu 2.4 inch với điều khiển bàn phím 4 hướng, bàn đạp, PLC hoặc USB"]} },
  "nexus-ii": { intro: {"en": "A water-cooled high power UV LED system offering quiet operation and rugged reliability in tough environments, with Ethernet communications and easy mounting with a common form factor. Well suited to flexographic printing applications.", "zh": "水冷式高功率UV LED系统，运行安静，在恶劣环境下坚固可靠，支持以太网通信，采用通用结构便于安装。适用于柔印等印刷应用场景。", "vi": "Hệ thống UV LED công suất cao làm mát bằng nước, vận hành êm ái và bền bỉ trong môi trường khắc nghiệt, hỗ trợ giao tiếp Ethernet và dễ lắp đặt với kích thước tiêu chuẩn. Phù hợp cho ứng dụng in flexo."}, features: {"en": ["Higher dose than the air-cooled variant — highest total UV energy for flexographic printing", "Wider web: up to 675 mm, with print speeds up to 1050 ft (320 m)/min", "90 W per cm maximum electrical power; >60,000 h diode life at L90", "ValidCure Technology; up to 60% less energy; 5-year full-system warranty"], "zh": ["剂量高于风冷版本——柔印领域最高总UV能量", "更宽幅面:最宽达675 mm，印刷速度可达1050 ft (320 m)/min", "最大电功率90 W/cm;二极管寿命>60,000小时(L90)", "ValidCure技术;节电达60%;整机5年质保"], "vi": ["Liều cao hơn phiên bản làm mát bằng khí — tổng năng lượng UV cao nhất cho in flexo", "Khổ rộng hơn: đến 675 mm, tốc độ in đến 1050 ft (320 m)/phút", "Công suất điện tối đa 90 W/cm; tuổi thọ diode >60.000 giờ (L90)", "Công nghệ ValidCure; tiết kiệm đến 60% điện; bảo hành toàn hệ thống 5 năm"]} },
  "nexus-ii-ac": { intro: {"en": "An air-cooled UV LED system with reduced routine maintenance and no chiller needed, offering Ethernet communications and easy mounting with a common form factor. Well suited to flexographic printing applications.", "zh": "风冷式UV LED系统，日常维护需求更低，无需配置冷水机，支持以太网通信，采用通用结构便于安装。适用于柔印等印刷应用场景。", "vi": "Hệ thống UV LED làm mát bằng khí giảm bảo trì định kỳ và không cần máy làm lạnh, hỗ trợ giao tiếp Ethernet và dễ lắp đặt với kích thước tiêu chuẩn. Phù hợp cho ứng dụng in flexo."}, features: {"en": ["No chiller or blower needed — the most energy-efficient Nexus II (up to 70% less kWh)", "Web width 300 – 600 mm; print speeds up to 720 ft (220 m)/min", "65 W per cm maximum electrical power; 45 °C maximum operating temperature", "ValidCure Technology; quick retrofit to any press; 5-year full-system warranty"], "zh": ["无需冷水机或风机——Nexus II中最节能型号(节电达70%)", "幅面300 – 600 mm;印刷速度可达720 ft (220 m)/min", "最大电功率65 W/cm;最高工作温度45°C", "ValidCure技术;快速加装到任意印刷机;整机5年质保"], "vi": ["Không cần máy làm lạnh hay quạt thổi — Nexus II tiết kiệm điện nhất (giảm đến 70% kWh)", "Khổ rộng 300 – 600 mm; tốc độ in đến 720 ft (220 m)/phút", "Công suất điện tối đa 65 W/cm; nhiệt độ vận hành tối đa 45 °C", "Công nghệ ValidCure; lắp thêm nhanh vào mọi máy in; bảo hành toàn hệ thống 5 năm"]} },
  "r2000": { intro: {"en": "Radiometry is essential for measuring UV light output to maintain a repeatable curing process. The R2000 Radiometer combines with the S2000 Elite/S2000 UV Spot Curing System to provide a complete curing station with unmatched control and repeatability. Special electronics allow connection of custom sensors that measure light energy directly at the cure site or within cure ring bonding fixtures.", "zh": "辐射测量是维持可重复UV光固化工艺的关键技术，用于测量UV光输出。R2000辐射计可与S2000 Elite/S2000 UV点固化系统配合使用，组成具备无可比拟控制力与重复精度的完整固化工作站。其特殊电路设计支持连接定制传感器，可直接在固化点或固化环夹具内测量光能。", "vi": "Đo bức xạ là kỹ thuật thiết yếu để đo đầu ra ánh sáng UV nhằm duy trì quy trình đóng rắn có thể lặp lại. Máy đo bức xạ R2000 có thể kết hợp với Hệ thống đóng rắn điểm UV S2000 Elite/S2000 để tạo thành trạm đóng rắn hoàn chỉnh với khả năng kiểm soát và độ lặp lại vượt trội. Mạch điện tử đặc biệt cho phép kết nối cảm biến tùy chỉnh để đo năng lượng ánh sáng trực tiếp tại điểm đóng rắn hoặc trong đồ gá vòng đóng rắn."}, features: {"en": ["Combines with S2000 Elite/S2000 for complete curing station control", "Supports custom sensors for cure site and cure ring measurement"], "zh": ["可与S2000 Elite/S2000配合，组成完整固化工作站控制方案", "支持连接定制传感器，用于固化点和固化环测量"], "vi": ["Kết hợp với S2000 Elite/S2000 để kiểm soát trạm đóng rắn hoàn chỉnh", "Hỗ trợ cảm biến tùy chỉnh để đo tại điểm đóng rắn và vòng đóng rắn"]} },
  "s1500-pro": { intro: {"en": "The latest addition to the OmniCure S-series lamp-based spot curing solutions, ideal for high-throughput UV adhesive curing and automated bonding processes in micro-electronic and opto-electronic manufacturing. Features Intelli-Lamp 2.0 technology, user-interchangeable optical filters, integrated StepCure 2.0, USB and SD card connectivity, and an intuitive LCD touch screen.", "zh": "OmniCure S系列灯式点固化解决方案的最新成员，适用于微电子和光电制造中高产能的UV胶水固化与自动化粘接工艺。配备Intelli-Lamp 2.0技术、用户可更换光学滤镜、集成StepCure 2.0、USB与SD卡连接，以及直观的液晶触摸屏界面。", "vi": "Sản phẩm mới nhất trong dòng giải pháp đóng rắn điểm sử dụng đèn của OmniCure S-series, lý tưởng cho quy trình đóng rắn keo UV và liên kết tự động hóa năng suất cao trong sản xuất vi điện tử và quang điện tử. Trang bị công nghệ Intelli-Lamp 2.0, bộ lọc quang có thể thay thế, StepCure 2.0 tích hợp, kết nối USB và thẻ SD, cùng màn hình cảm ứng LCD trực quan."}, features: {"en": ["Intelli-Lamp 2.0 technology enhances lamp life while maintaining performance", "User-interchangeable and customizable optical filters", "Industry 4.0 ready with programmable PLC output, Flight Recorder log, and NFC key card"], "zh": ["Intelli-Lamp 2.0技术延长灯泡寿命同时保持性能", "用户可更换、可定制的光学滤镜", "支持工业4.0，配备可编程PLC输出、飞行记录器日志和NFC密钥卡"], "vi": ["Công nghệ Intelli-Lamp 2.0 kéo dài tuổi thọ đèn trong khi duy trì hiệu suất", "Bộ lọc quang có thể thay thế và tùy chỉnh bởi người dùng", "Sẵn sàng Industry 4.0 với đầu ra PLC lập trình được, nhật ký Flight Recorder và thẻ khóa NFC"]} },
  "s2000-elite": { intro: {"en": "A new generation lamp-based UV spot curing system designed for the most demanding manufacturing applications. Offers a powerful 200 Watt lamp with a guaranteed life of 2000 hours, proprietary Closed-Loop Feedback technology that monitors light output in real time and automatically corrects within +/-5%, a 4.3\" touch screen, and StepCure 2.0 with 7 programmable PLC output channels for Industry 4.0 integration.", "zh": "新一代灯式UV点固化系统，专为最严苛的制造应用而设计。配备200瓦大功率灯，保证寿命2000小时；搭载专利闭环反馈（Closed-Loop Feedback）技术，实时监测光输出并自动修正，误差控制在±5%以内；配有4.3英寸触摸屏，以及具备7个可编程PLC输出通道的StepCure 2.0系统，可轻松接入工业4.0环境。", "vi": "Hệ thống đóng rắn UV điểm thế hệ mới sử dụng đèn, được thiết kế cho các ứng dụng sản xuất khắt khe nhất. Trang bị đèn công suất 200W với tuổi thọ bảo hành 2000 giờ, công nghệ phản hồi vòng kín (Closed-Loop Feedback) độc quyền giám sát đầu ra ánh sáng theo thời gian thực và tự động hiệu chỉnh trong phạm vi ±5%, màn hình cảm ứng 4.3 inch, cùng StepCure 2.0 với 7 kênh đầu ra PLC lập trình được, sẵn sàng tích hợp Industry 4.0."}, features: {"en": ["Closed-Loop Feedback and Intelli-lamp technology guarantee precise dosage delivery", "Plug-and-play compatibility with existing S2000/S1500 production lines", "Calibration with OmniCure R2000 Radiometer, remote control via WEB UI", "StepCure 2.0 with PLC control enhances automation for Industry 4.0"], "zh": ["闭环反馈与Intelli-lamp技术确保精准剂量输出", "即插即用，兼容现有S2000/S1500生产线", "可配合OmniCure R2000辐射计校准，支持WEB UI远程控制管理", "StepCure 2.0配合PLC控制，提升自动化水平，适配工业4.0"], "vi": ["Công nghệ phản hồi vòng kín và Intelli-lamp đảm bảo cấp liều chính xác", "Tương thích cắm-và-chạy với dây chuyền sản xuất S2000/S1500 hiện có", "Hiệu chuẩn cùng máy đo bức xạ OmniCure R2000, điều khiển từ xa qua WEB UI", "StepCure 2.0 với điều khiển PLC tăng cường tự động hóa cho Industry 4.0"]} },
  "semray-5000": { intro: {"en": "Designed for higher performance and flexible integration especially for larger working distances, the Semray UV5000+ Series is a water-cooled system. The emission window size is scalable in width from 400 to 1300mm in 50mm steps, with housing dimensions scalable accordingly.", "zh": "Semray UV5000+系列为水冷式系统，专为更高性能与灵活集成而设计，尤其适合较大工作距离的应用场景。发光窗口宽度可在400至1300毫米范围内以50毫米为步进进行调整，外壳尺寸相应可调。", "vi": "Được thiết kế cho hiệu suất cao hơn và tích hợp linh hoạt, đặc biệt phù hợp với khoảng cách làm việc lớn hơn, dòng Semray UV5000+ là hệ thống làm mát bằng nước. Kích thước cửa sổ phát quang có thể điều chỉnh theo chiều rộng từ 400 đến 1300mm theo bước 50mm, kích thước vỏ máy điều chỉnh tương ứng."}, features: {"en": ["Designed for larger working distances with flexible integration", "Emission window scalable from 400 to 1300mm in 50mm steps"], "zh": ["专为大工作距离与灵活集成而设计", "发光窗口宽度可在400至1300毫米之间以50毫米为步进调整"], "vi": ["Thiết kế cho khoảng cách làm việc lớn với tích hợp linh hoạt", "Cửa sổ phát quang điều chỉnh từ 400 đến 1300mm theo bước 50mm"]} },
  "semray-pc6003": { intro: {"en": "A UV LED curing system designed from the ground up for optical fiber draw and wire marking manufacturing processes, providing 360° curing coverage.", "zh": "UV PC6003是一款从零开始专为光纤拉丝与线材标识制造工艺设计的UV LED固化系统，提供360°全方位固化覆盖。", "vi": "Hệ thống đóng rắn UV LED được thiết kế từ đầu cho quy trình sản xuất kéo sợi quang và đánh dấu dây, cung cấp phạm vi đóng rắn 360°."}, features: {"en": ["Purpose-built for optical fiber draw and wire marking processes", "360° curing coverage"], "zh": ["专为光纤拉丝与线材标识工艺打造", "360°全方位固化覆盖"], "vi": ["Được chế tạo riêng cho quy trình kéo sợi quang và đánh dấu dây", "Phạm vi đóng rắn 360°"]} },
  "semray-uv5052m": { intro: {"en": "Equipped with special optics to bring more energy to the process, the Semray UV5052M is an example of customized UV LED development. A set of unique optical concepts direct photons from the UV-LED chips to larger working distances for greater flexibility in applications, minimum loss of energy and straylight, and focused UV intensity.", "zh": "UV5052M配备特殊光学系统，可为工艺过程提供更高能量，是Semray定制化UV LED开发的代表案例之一。独特的光学设计可将UV-LED芯片发出的光子引导至更大的工作距离，从而提升应用灵活性、最大限度降低能量损耗与杂散光，并实现聚焦的UV强度输出。", "vi": "Được trang bị quang học đặc biệt để mang lại nhiều năng lượng hơn cho quy trình, Semray UV5052M là ví dụ điển hình của phát triển UV LED tùy chỉnh. Một loạt khái niệm quang học độc đáo định hướng photon từ chip UV-LED đến khoảng cách làm việc lớn hơn, mang lại tính linh hoạt cao hơn trong ứng dụng, giảm thiểu thất thoát năng lượng và tán xạ, và cường độ UV tập trung."}, features: {"en": ["Dedicated optics for high intensity even at large working distances", "Customizable in sizes, lengths, connections, and optical concepts"], "zh": ["专用光学设计，即使在大工作距离下也能保持高强度", "尺寸、长度、接口及光学方案均可定制"], "vi": ["Quang học chuyên dụng cho cường độ cao ngay cả ở khoảng cách làm việc lớn", "Có thể tùy chỉnh về kích thước, chiều dài, kết nối và khái niệm quang học"]} },
  "vericure": { intro: {"en": "A water-cooled UV LED system delivering ultra-high UV dose in a wide lamp format, up to 500 mJ/cm2 dose at 50mm working distance. Offers quiet operation and rugged reliability in tough environments, with Ethernet and analog communications. Well suited to high performance applications such as wood coatings.", "zh": "水冷式UV LED系统，以宽幅灯具形式提供超高UV剂量，工作距离50毫米时剂量最高可达500 mJ/cm²。运行安静，在恶劣环境下坚固可靠，支持以太网与模拟通信。适用于木材涂层等高性能应用场景。", "vi": "Hệ thống UV LED làm mát bằng nước cung cấp liều UV siêu cao ở định dạng đèn rộng, đạt tới 500 mJ/cm² ở khoảng cách làm việc 50mm. Vận hành êm ái và độ bền cao trong môi trường khắc nghiệt, hỗ trợ giao tiếp Ethernet và tương tự. Phù hợp cho ứng dụng hiệu suất cao như sơn phủ gỗ."}, features: {"en": ["Ultra-high UV dose up to 500 mJ/cm2 at 50mm working distance", "Quiet operation, rugged and reliable in tough environments", "Ethernet and analog communications, easy mounting with common form factor"], "zh": ["超高UV剂量，50毫米工作距离下最高可达500 mJ/cm²", "运行安静，在恶劣环境下坚固可靠", "支持以太网与模拟通信，采用通用结构便于安装"], "vi": ["Liều UV siêu cao lên đến 500 mJ/cm² ở khoảng cách làm việc 50mm", "Vận hành êm ái, bền bỉ và đáng tin cậy trong môi trường khắc nghiệt", "Giao tiếp Ethernet và tương tự, dễ lắp đặt với kích thước tiêu chuẩn"]} },
  "v3-led-heads": { intro: {"en": "Designed for use with the OmniCure LX500 Controller, the OmniCure V3 UV LED Heads feature next-generation high-output UV LEDs delivering best-in-class optical performance. With up to 120% increased optical power and up to 165% increase in peak irradiance compared to the predecessor MAX LED Heads, the V3 Heads deliver high dosage distributed uniformly across the spot area for faster, more consistent cures with greater control. Available in 365, 385, 395 and 405 nm wavelengths, delivering up to 22 W/cm² peak irradiance and 1,100 mW power with an exceptionally uniform beam profile.", "zh": "OmniCure V3 UV LED Heads 专为搭配 OmniCure LX500 Controller 使用而设计，采用新一代高输出 UV LED，提供同类领先的光学性能。与上一代 MAX LED Heads 相比，光功率提升最高达 120%，峰值辐照度提升最高达 165%，V3 Heads 可在点固化区域内均匀分布高剂量，实现更快、更一致且控制性更强的固化。提供 365、385、395 和 405 nm 波长，峰值辐照度最高达 22 W/cm²，功率达 1,100 mW，并具有极为均匀的光束轮廓。", "vi": "Được thiết kế để sử dụng với OmniCure LX500 Controller, OmniCure V3 UV LED Heads sử dụng UV LED công suất cao thế hệ mới, mang lại hiệu suất quang hàng đầu trong phân khúc. Với công suất quang tăng tới 120% và độ rọi đỉnh tăng tới 165% so với MAX LED Heads thế hệ trước, V3 Heads cung cấp liều cao phân bố đồng đều trên vùng điểm, giúp đóng rắn nhanh hơn, đồng nhất hơn và kiểm soát tốt hơn. Có sẵn ở các bước sóng 365, 385, 395 và 405 nm, mang lại độ rọi đỉnh tới 22 W/cm² và công suất 1,100 mW với biên dạng chùm tia cực kỳ đồng đều."}, features: {"en": ["Class-leading irradiance and optical power at 365, 385, 395 and 405 nm", "Up to 22 W/cm² peak irradiance and 1,100 mW total optical power", "Improved radiation distribution across the beam cross-section for consistent, controlled curing", "Up to 120% increased optical power vs. predecessor MAX LED Heads", "More energy efficient, lower maintenance, and longer service life", "Wide range of cross-compatible accessories: focusing lenses, adapters, extension cables", "Backward compatible with existing LX500 Controller", "Paired with LX500 for outstanding ±5% optical stability"], "zh": ["在 365、385、395 和 405 nm 下具有同类领先的辐照度和光功率", "峰值辐照度最高达 22 W/cm²，总光功率达 1,100 mW", "改善光束横截面的辐射分布，实现一致、可控的固化", "与上一代 MAX LED Heads 相比，光功率提升最高达 120%", "更节能、更低维护、更长使用寿命", "多种交叉兼容配件：聚焦透镜、适配器、延长线缆", "向后兼容现有的 LX500 Controller", "与 LX500 搭配使用，实现出色的 ±5% 光学稳定性"], "vi": ["Độ rọi và công suất quang hàng đầu phân khúc ở 365, 385, 395 và 405 nm", "Độ rọi đỉnh tới 22 W/cm² và tổng công suất quang 1,100 mW", "Cải thiện phân bố bức xạ trên tiết diện chùm tia để đóng rắn đồng nhất và có kiểm soát", "Công suất quang tăng tới 120% so với MAX LED Heads thế hệ trước", "Tiết kiệm năng lượng hơn, bảo trì ít hơn và tuổi thọ dài hơn", "Nhiều phụ kiện tương thích chéo: thấu kính hội tụ, bộ chuyển đổi, cáp nối dài", "Tương thích ngược với LX500 Controller hiện có", "Kết hợp với LX500 để đạt độ ổn định quang ±5% xuất sắc"]} },
  "s2e-network-module": { intro: {"en": "The OmniCure S2E Network Module is designed to save time on maintenance and keep production running smoothly with remote process monitoring and UV curing equipment control. The S2E complements the OmniCure family of S-Series spot UV curing systems, offering the same high level of innovation, quality and reliability that customers expect. The S2E Ethernet adapter enables production facilities to remotely access up to 300 UV curing systems within a local area network, while simultaneously monitoring their activity and maintenance requirements through the OmniCure Monitoring Station software.", "zh": "OmniCure S2E Network Module 旨在通过远程过程监控和 UV 光固化设备控制，节省维护时间并保持生产顺畅运行。S2E 是 OmniCure S-Series 点固化系统家族的补充产品，提供客户所期望的同等高水平创新、质量和可靠性。S2E 以太网适配器使生产设施能够在局域网内远程访问多达 300 台 UV 光固化系统，同时通过 OmniCure Monitoring Station 软件监控其运行活动和维护需求。", "vi": "OmniCure S2E Network Module được thiết kế để tiết kiệm thời gian bảo trì và giữ cho sản xuất vận hành trơn tru thông qua giám sát quy trình từ xa và điều khiển thiết bị đóng rắn UV. S2E bổ sung cho dòng hệ thống đóng rắn UV điểm S-Series của OmniCure, mang lại cùng mức độ đổi mới, chất lượng và độ tin cậy cao mà khách hàng mong đợi. Bộ chuyển đổi Ethernet S2E cho phép các cơ sở sản xuất truy cập từ xa tới 300 hệ thống đóng rắn UV trong một mạng cục bộ, đồng thời giám sát hoạt động và nhu cầu bảo trì của chúng thông qua phần mềm OmniCure Monitoring Station."}, features: {"en": ["Save maintenance time and keep production running smoothly with OmniCure Monitoring Station software", "Proactively trend and predict maintenance requirements with continuous operational data logging", "Enhance visibility of production activity and quickly isolate issues that result in potential waste/rework", "Increase productivity and eliminate time lost identifying system faults with real-time email alerts", "Remotely access and monitor up to 300 UV curing systems on a local area network", "Adds StepCure process functionality to the S1500"], "zh": ["借助 OmniCure Monitoring Station 软件节省维护时间并保持生产顺畅运行", "通过持续的运行数据记录，主动分析趋势并预测维护需求", "提升生产活动的可视性，快速定位可能导致浪费/返工的问题", "通过实时邮件警报提高生产率，消除识别系统故障所浪费的时间", "在局域网上远程访问和监控多达 300 台 UV 光固化系统", "为 S1500 增加 StepCure 工艺功能"], "vi": ["Tiết kiệm thời gian bảo trì và giữ sản xuất vận hành trơn tru với phần mềm OmniCure Monitoring Station", "Chủ động phân tích xu hướng và dự đoán nhu cầu bảo trì với ghi dữ liệu vận hành liên tục", "Tăng khả năng hiển thị hoạt động sản xuất và nhanh chóng khoanh vùng các vấn đề có thể gây lãng phí/làm lại", "Tăng năng suất và loại bỏ thời gian mất đi khi xác định lỗi hệ thống nhờ cảnh báo email theo thời gian thực", "Truy cập và giám sát từ xa tới 300 hệ thống đóng rắn UV trên mạng cục bộ", "Bổ sung chức năng quy trình StepCure cho S1500"]} },
  "s-series-light-guides": { intro: {"en": "The OmniCure S Series offers a variety of light guides ranging from single and multi-legged to liquid-filled or fiber light guides, as well as a range of optical adapters to best meet customer requirements.", "zh": "OmniCure S Series 提供多种导光管，从单支和多支到液体填充或光纤导光管，以及一系列光学适配器，以最佳满足客户需求。", "vi": "OmniCure S Series cung cấp nhiều loại ống dẫn sáng, từ loại một nhánh và nhiều nhánh đến ống dẫn sáng chứa chất lỏng hoặc sợi quang, cùng với một loạt bộ chuyển đổi quang học để đáp ứng tốt nhất yêu cầu của khách hàng."}, features: {"en": ["Liquid Light Guide: 3, 5 and 8 mm tip diameters; standard lengths 750–3000 mm; dual and triple-leg configurations for multi-site curing", "High-Power Fiber Light Guide: equal distribution of light energy to multiple cure sites from a single light source", "High-Power Fiber Light Line: high-output linear beam; continuous fibers from input to termination eliminate coupling losses", "UV Cure-Ring Optical Adapter: 360° curing power; solid or slotted versions for Liquid Light Guides", "UV Light-Line Optical Adapter: focused linear beam for small rows of components, tubing and cables (up to 2\" line length)", "Adjustable Spot Collimating Adapter: uniform spot from 1\" up to 6\" (2.54–15.2 cm) for even power distribution"], "zh": ["液体导光管：尖端直径 3、5 和 8 mm；标准长度 750–3000 mm；双支和三支配置，适用于多点固化", "高功率光纤导光管：将光能从单一光源均匀分配到多个固化点", "高功率光纤光线：高输出线性光束；从输入到端接的连续光纤消除耦合损耗", "UV Cure-Ring 光学适配器：360° 固化功率；适用于液体导光管的实心或开槽版本", "UV Light-Line 光学适配器：聚焦线性光束，适用于小排元件、管材和线缆（线长最长 2\"）", "可调点准直适配器：均匀光斑范围从 1\" 到 6\"（2.54–15.2 cm），实现均匀的功率分布"], "vi": ["Ống dẫn sáng lỏng: đường kính đầu 3, 5 và 8 mm; chiều dài tiêu chuẩn 750–3000 mm; cấu hình hai nhánh và ba nhánh cho đóng rắn nhiều điểm", "Ống dẫn sáng sợi quang công suất cao: phân bố năng lượng ánh sáng đều đến nhiều điểm đóng rắn từ một nguồn sáng duy nhất", "Đường sáng sợi quang công suất cao: chùm tia tuyến tính công suất cao; sợi quang liên tục từ đầu vào đến đầu cuối loại bỏ tổn hao ghép nối", "Bộ chuyển đổi quang học UV Cure-Ring: công suất đóng rắn 360°; phiên bản đặc hoặc có rãnh cho ống dẫn sáng lỏng", "Bộ chuyển đổi quang học UV Light-Line: chùm tia tuyến tính hội tụ cho các hàng nhỏ linh kiện, ống và cáp (chiều dài đường tới 2\")", "Bộ chuyển đổi chuẩn trực điểm có thể điều chỉnh: điểm đồng đều từ 1\" đến 6\" (2.54–15.2 cm) để phân bố công suất đều"]} },
  "fl400-i": { intro: {"en": "The FireLine FL400-i Industrial UV LED Area Curing System is specifically designed for demanding industrial coating and adhesive curing in harsh, high-contaminant environments such as pipe coating and metal finishing. It features a newly engineered IP66-rated enclosure with robust endcaps, advanced window sealing, and optional sacrificial glass to shield primary optics from heat, dust and impact — delivering the same industry-leading optical uniformity and high dose performance as the original FL400.", "zh": "FireLine FL400-i 工业 UV LED 面固化系统专为在管道涂层和金属表面处理等严苛、高污染环境中进行高要求的工业涂层和胶粘剂固化而设计。它采用全新设计的 IP66 级外壳，配备坚固的端盖、先进的窗口密封以及可选的牺牲玻璃(保护玻璃)，可保护主光学元件免受热量、灰尘和冲击的影响，同时提供与原版 FL400 相同的行业领先光学均匀性和高剂量性能。", "vi": "Hệ thống đóng rắn UV LED diện tích công nghiệp FireLine FL400-i được thiết kế đặc biệt cho việc đóng rắn lớp phủ và keo dán công nghiệp đòi hỏi khắt khe trong môi trường khắc nghiệt, nhiều chất bẩn như phủ ống và xử lý bề mặt kim loại. Nó có vỏ đạt chuẩn IP66 được thiết kế mới với nắp đầu chắc chắn, gioăng kín cửa sổ tiên tiến và kính bảo vệ tùy chọn để che chắn quang học chính khỏi nhiệt, bụi và va đập — mang lại cùng độ đồng đều quang học hàng đầu ngành và hiệu suất liều cao như FL400 nguyên bản."}, features: {"en": ["IP66-rated ruggedized enclosure for harsh, high-contaminant environments", "Advanced window sealing protects against heat, liquid, and dirt intrusion", "Versatile connection options: straight or barbed water fittings", "CDA (clean, dry air) ports to protect against condensation", "Optional sacrificial glass to shield primary optics", "Same optical uniformity and high dose performance as FL400", "Robust endcaps engineered for challenging industrial environments"], "zh": ["IP66 级坚固外壳，适用于严苛、高污染环境", "先进的窗口密封，防止热量、液体和污垢侵入", "多样的连接选项：直式或倒钩式水接头", "CDA（清洁干燥空气）端口，防止冷凝", "可选牺牲玻璃(保护玻璃)，保护主光学元件", "与 FL400 相同的光学均匀性和高剂量性能", "坚固的端盖，专为严苛的工业环境设计"], "vi": ["Vỏ gia cố đạt chuẩn IP66 cho môi trường khắc nghiệt, nhiều chất bẩn", "Gioăng kín cửa sổ tiên tiến bảo vệ chống nhiệt, chất lỏng và bụi bẩn xâm nhập", "Tùy chọn kết nối đa dạng: khớp nối nước thẳng hoặc có ngạnh", "Cổng CDA (khí sạch, khô) để chống ngưng tụ", "Kính bảo vệ tùy chọn để che chắn quang học chính", "Độ đồng đều quang học và hiệu suất liều cao giống như FL400", "Nắp đầu chắc chắn được thiết kế cho môi trường công nghiệp đầy thách thức"]} },
  "fe400": { intro: {"en": "The FireEdge FE400 air-cooled UV LED curing system offers advanced features with maximum flexibility, including built-in intensity control for both full-cure and UV inkjet pinning applications. It features patented Semiconductor Light Matrix (SLM) technology for process stability and is available in lengths from 80 mm to 240 mm. Segment control allows half the light source to be disabled for precise UV coverage, and a Hub can manage up to six light sources.", "zh": "FireEdge FE400 风冷 UV LED 固化系统提供先进的功能和最大的灵活性，包括内置强度控制，适用于完全固化和 UV 喷墨预固化(定位固化)应用。它采用专利 Semiconductor Light Matrix (SLM) 技术以确保工艺稳定性，长度从 80 mm 到 240 mm 不等。分段控制可禁用一半光源以实现精确的 UV 覆盖，一个 Hub 最多可管理六个光源。", "vi": "Hệ thống đóng rắn UV LED làm mát bằng khí FireEdge FE400 mang lại các tính năng tiên tiến với độ linh hoạt tối đa, bao gồm điều khiển cường độ tích hợp cho cả ứng dụng đóng rắn hoàn toàn và định vị sơ bộ (pinning) UV inkjet. Nó sử dụng công nghệ Semiconductor Light Matrix (SLM) được cấp bằng sáng chế để ổn định quy trình và có sẵn với chiều dài từ 80 mm đến 240 mm. Điều khiển phân đoạn cho phép tắt một nửa nguồn sáng để phủ UV chính xác, và một Hub có thể quản lý tối đa sáu nguồn sáng."}, features: {"en": ["Built-in intensity control: full-cure, low-intensity (pinning), and half-source modes", "Patented SLM technology for process stability and repeatable output", "Available lengths: 80, 120, 160, 180, 240 mm", "Air-cooled — no water connections required", "Segment control: disable left or right half for precise UV coverage", "Scalable: stack end-to-end for contiguous uniform UV output", "Hub supports up to six light sources, managed as a single unit"], "zh": ["内置强度控制：完全固化、低强度（预固化(定位固化)）和半光源模式", "专利 SLM 技术，确保工艺稳定性和可重复的输出", "可选长度：80、120、160、180、240 mm", "风冷 — 无需水连接", "分段控制：禁用左半或右半以实现精确的 UV 覆盖", "可扩展：端对端堆叠，实现连续均匀的 UV 输出", "Hub 最多支持六个光源，作为单一单元进行管理"], "vi": ["Điều khiển cường độ tích hợp: chế độ đóng rắn hoàn toàn, cường độ thấp (định vị sơ bộ) và nửa nguồn sáng", "Công nghệ SLM được cấp bằng sáng chế để ổn định quy trình và đầu ra lặp lại", "Chiều dài có sẵn: 80, 120, 160, 180, 240 mm", "Làm mát bằng khí — không cần kết nối nước", "Điều khiển phân đoạn: tắt nửa trái hoặc phải để phủ UV chính xác", "Có thể mở rộng: xếp chồng đầu nối đầu để có đầu ra UV liền mạch, đồng đều", "Hub hỗ trợ tối đa sáu nguồn sáng, được quản lý như một đơn vị duy nhất"]} },
  "fj800": { intro: {"en": "The Phoseon FireJet FJ800 UV LED Curing System is a large-area curing solution for adhesive and coating applications requiring low irradiance and long dwell time on large-scale production lines. Starting with a 100 mm × 100 mm base curing area, the modular components scale in all four directions, providing contiguous, uniform UV illumination. Operated by a simple controller supporting up to six light sources, the FJ800 is available in 365 and 395 nm wavelengths.", "zh": "Phoseon FireJet FJ800 UV LED 固化系统是一种大面积固化解决方案，适用于在大规模生产线上需要低辐照度和长停留时间的胶粘剂和涂层应用。以 100 mm × 100 mm 基础固化区域为起点，模块化组件可向四个方向扩展，提供连续、均匀的 UV 照射。FJ800 由支持多达六个光源的简易控制器操控，提供 365 和 395 nm 波长。", "vi": "Hệ thống đóng rắn UV LED Phoseon FireJet FJ800 là giải pháp đóng rắn diện tích lớn cho các ứng dụng keo dán và lớp phủ yêu cầu độ rọi thấp và thời gian lưu dài trên các dây chuyền sản xuất quy mô lớn. Bắt đầu với vùng đóng rắn cơ sở 100 mm × 100 mm, các thành phần mô-đun mở rộng theo cả bốn hướng, cung cấp chiếu sáng UV liền mạch, đồng đều. Được vận hành bằng bộ điều khiển đơn giản hỗ trợ tối đa sáu nguồn sáng, FJ800 có sẵn ở các bước sóng 365 và 395 nm."}, features: {"en": ["Modular and scalable: 100 mm × 100 mm base, scalable in all four directions", "Contiguous, uniform UV output across the entire curing area", "Simple controller supporting up to six light sources", "Available wavelengths: 365, 395 nm", "Air-cooled for flexible, cost-effective integration", "Optimized for large-area curing requiring low irradiance and long dwell time"], "zh": ["模块化且可扩展：100 mm × 100 mm 基础单元，可向四个方向扩展", "在整个固化区域内提供连续、均匀的 UV 输出", "简易控制器，最多支持六个光源", "可选波长：365、395 nm", "风冷设计，实现灵活、经济高效的集成", "针对需要低辐照度和长停留时间的大面积固化进行了优化"], "vi": ["Mô-đun và có thể mở rộng: cơ sở 100 mm × 100 mm, mở rộng theo cả bốn hướng", "Đầu ra UV liền mạch, đồng đều trên toàn bộ vùng đóng rắn", "Bộ điều khiển đơn giản hỗ trợ tối đa sáu nguồn sáng", "Bước sóng có sẵn: 365, 395 nm", "Làm mát bằng khí để tích hợp linh hoạt, hiệu quả về chi phí", "Tối ưu cho đóng rắn diện tích lớn yêu cầu độ rọi thấp và thời gian lưu dài"]} },
  "drf-series": { intro: {"en": "The Fusion UV DRF Series cure photoresponsive coatings, coloring inks, and ribbon matrix polymers in the production of optical fiber and cable. The DRF Series has been the UV curing system of choice for fiber manufacturing worldwide, thanks to its patented secondary elliptical reflector system that delivers highly focused, intense UV energy. The optical fiber passes through a sealed quartz tube aligned at the secondary focal point of the elliptical reflector for full-surface UV exposure. DRF systems support power levels from 1.8 kW (F300S) to 6 kW.", "zh": "Fusion UV DRF Series 在光纤和线缆的生产中固化光响应涂层、着色油墨和带状矩阵聚合物。凭借其专利的二次椭圆反射器系统，可提供高度聚焦、强烈的 UV 能量，DRF Series 已成为全球光纤制造的首选 UV 光固化系统。光纤穿过对准椭圆反射器二次焦点的密封石英管，实现全表面 UV 曝光。DRF 系统支持从 1.8 kW (F300S) 到 6 kW 的功率等级。", "vi": "Fusion UV DRF Series đóng rắn các lớp phủ nhạy quang, mực màu và polymer ma trận dạng dải trong sản xuất sợi quang và cáp. DRF Series đã là hệ thống đóng rắn UV được lựa chọn cho sản xuất sợi quang trên toàn thế giới, nhờ hệ thống gương phản xạ elip thứ cấp được cấp bằng sáng chế mang lại năng lượng UV cường độ cao, hội tụ cao. Sợi quang đi qua một ống thạch anh kín được căn chỉnh tại tiêu điểm thứ cấp của gương phản xạ elip để phơi UV toàn bề mặt. Hệ thống DRF hỗ trợ mức công suất từ 1.8 kW (F300S) đến 6 kW."}, features: {"en": ["Patented secondary elliptical reflector: highest UV irradiance per watt", "Highly focused, intense UV energy for optical fiber curing", "Sealed quartz tube enables full-surface UV exposure with minimal stray radiation", "Noblelight microwave-powered electrodeless lamp: stable, consistent UV output", "Reaches maximum curing power within seconds of ignition", "Modular design for easy maintenance and component replacement", "Interchangeable bulbs to match spectral output to coating needs", "Optional easy-align lamp mounting system", "Optional patented back reflector for enhanced UV efficiency", "Individual lamp switching in multi-lamp setups for line-speed adjustment"], "zh": ["专利二次椭圆反射器：每瓦最高 UV 辐照度", "高度聚焦、强烈的 UV 能量，用于光纤固化", "密封石英管实现全表面 UV 曝光，杂散辐射极小", "Noblelight 微波驱动无极灯：稳定、一致的 UV 输出", "点火后数秒内达到最大固化功率", "模块化设计，便于维护和更换组件", "可互换灯泡，使光谱输出与涂层需求相匹配", "可选的易对准灯安装系统", "可选的专利背面反射器，提升 UV 效率", "在多灯配置中可单独切换灯，以调整线速度"], "vi": ["Gương phản xạ elip thứ cấp được cấp bằng sáng chế: độ rọi UV cao nhất trên mỗi watt", "Năng lượng UV cường độ cao, hội tụ cao cho đóng rắn sợi quang", "Ống thạch anh kín cho phép phơi UV toàn bề mặt với bức xạ tản lạc tối thiểu", "Đèn không điện cực được cấp nguồn bằng vi sóng Noblelight: đầu ra UV ổn định, đồng nhất", "Đạt công suất đóng rắn tối đa trong vòng vài giây sau khi khởi động", "Thiết kế mô-đun để dễ dàng bảo trì và thay thế linh kiện", "Bóng đèn có thể thay thế lẫn nhau để phù hợp đầu ra quang phổ với nhu cầu lớp phủ", "Hệ thống lắp đèn dễ căn chỉnh tùy chọn", "Gương phản xạ sau được cấp bằng sáng chế tùy chọn để nâng cao hiệu suất UV", "Chuyển đổi đèn riêng lẻ trong cấu hình nhiều đèn để điều chỉnh tốc độ dây chuyền"]} },
};

